// === Heating controller — House Mode + time + 2h BOOST + forecast pre-heat (02-07-2026; dash boost 04-07-2026) ===
// Netatmo holds flat eco 18.5 baseline; this flow only RAISES via HomeKit set_temperature.
// Out1 -> set thermostat; Out2 -> test notify (change only, quiet 22:00-07:00); Out3 -> input_text.heating_status.
const TEMP = { eco: 18.5, comfort: 20, night: 19.5, hot: 20.5, frost: 12 };
const BOOST_MS = 2 * 60 * 60 * 1000;   // manual override holds 2 hours
const MORNING_HOUR = 7;                // morning comfort warm-up starts 07:00 (base; forecast can bring earlier)
const PROX_M = 10000;                  // proximity pre-heat: within 10 km AND heading towards home -> comfort

const ents = Array.isArray(msg.payload) ? msg.payload : [];
const get = id => ents.find(e => e.entity_id === id);
const ds = d => d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0') + '-' + String(d.getDate()).padStart(2, '0');

// Guest mode: ONLY block Away (never let the house go cold with guests in);
// Sleeping and Home run as normal (overnight 19.5, 7am warm-up, forecast pre-heat all still apply).
const guestOn = (() => { const g = get('input_boolean.guest_mode'); return g ? g.state === 'on' : false; })();
const hmRaw = (get('input_select.house_mode') || {}).state || 'Home';
const hm = (guestOn && hmRaw === 'Away') ? 'Home' : hmRaw;
const hmDisplay = guestOn ? hm + ' (guest)' : hm;
const mode = String(hm).toLowerCase();

// Extended-away 24h deep setback (helper defaults ON if absent)
const extToggle = get('input_boolean.heating_extended_away');
const extendedAwayEnabled = extToggle ? (extToggle.state === 'on') : true;
const EMPTY_LIMIT_MS = 24 * 60 * 60 * 1000;
let emptySince = context.get('emptySince');
if (mode === 'away') { if (!emptySince) emptySince = Date.now(); } else emptySince = null;
context.set('emptySince', emptySince);
const longAway = !!emptySince && (Date.now() - emptySince) >= EMPTY_LIMIT_MS;

const now = new Date();
const nowMs = Date.now();
const mins = now.getHours() * 60 + now.getMinutes();
const hour = now.getHours();
const between = (m, sH, sM, eH, eM) => m >= sH * 60 + sM && m < eH * 60 + eM;
const hhmm = ms => { const d = new Date(ms); return String(d.getHours()).padStart(2, '0') + ':' + String(d.getMinutes()).padStart(2, '0'); };

// --- scheduled target ---
let schedMode;
if (mode !== 'away') flow.set('preheat_latch', false);   // any exit from Away clears the pre-heat latch
if (mode === 'away') {
  // Proximity pre-heat: within 10 km AND heading towards home -> warm for arrival.
  // LATCHED: GPS direction flaps towards/stationary between fixes (glitch seen 05-07-2026:
  // setpoint bounced 20 -> 18.5 -> 20 mid-approach). Once on, pre-heat holds for the rest of
  // Away unless the person clearly leaves again (beyond PROX_CLEAR_M or distance unknown).
  const PROX_CLEAR_M = 12000;
  const pDist = parseFloat((get('sensor.12_the_oaks_nearest_distance') || {}).state);
  const pDir = (get('sensor.12_the_oaks_nearest_direction_of_travel') || {}).state;
  let preheat = flow.get('preheat_latch') || false;
  if (!isNaN(pDist) && pDist <= PROX_M && pDir === 'towards') preheat = true;
  if (isNaN(pDist) || pDist > PROX_CLEAR_M) preheat = false;
  flow.set('preheat_latch', preheat);
  schedMode = preheat ? 'comfort' : ((longAway && extendedAwayEnabled) ? 'frost' : 'eco');
} else if (mode === 'sleeping') {
  let sm = (hour >= MORNING_HOUR && hour < 12) ? 'comfort' : 'night';
  // Forecast pre-heat: bring the morning comfort forward on cold mornings (set nightly by the fc sub-flow)
  const ph = flow.get('preHeat');
  if (ph && ph.day === ds(now) && nowMs >= ph.startMs && hour < MORNING_HOUR) sm = 'comfort';
  schedMode = sm;
} else {
  schedMode = between(mins, 19, 0, 22, 0) ? 'hot' : 'comfort';
}
const schedTarget = TEMP[schedMode];

// --- manual boost detection (confirmed-setpoint method; immune to poll lag) ---
// A confirmed external setpoint change ABOVE the scheduled target = 2h boost.
// A change AT or BELOW the scheduled target (dial turned down / Netatmo app boost deleted ->
// device reverts to its 18.5 baseline) = CANCEL any boost; the schedule reasserts. Never a "boost down".
const climate = get('climate.netatmo_smart_thermostat');
const curSet = climate && climate.attributes ? climate.attributes.temperature : null;
const lastTarget = context.get('lastTarget');
let confirmed = context.get('confirmed') || false;
let boostUntil = context.get('boostUntil') || 0;
let boostTemp = context.get('boostTemp');
let boostNote = null; // overrides the notify text for boost cancel/decline

if (curSet != null && lastTarget != null && curSet === lastTarget) confirmed = true;
if (mode !== 'away' && confirmed && curSet != null && lastTarget != null && curSet !== lastTarget
    && !(boostUntil > nowMs && curSet === boostTemp)) {
  if (curSet > schedTarget) {
    boostTemp = curSet;
    boostUntil = nowMs + BOOST_MS;       // start / restart the 2h hold (never starts while Away)
  } else if (boostUntil > nowMs) {
    boostUntil = 0; boostTemp = null;    // turned down to/below schedule -> cancel boost
    boostNote = 'Boost cancelled - back to schedule';
  }
  context.set('boostTemp', boostTemp);
  context.set('boostUntil', boostUntil);
}
context.set('confirmed', confirmed);

// --- dashboard boost commands (input_buttons via msg.topic) ---
if (msg.topic === 'boost-start') {
  if (mode === 'away') {
    boostNote = 'Boost ignored - house is Away';
  } else {
    const bt = parseFloat((get('input_number.heating_boost_temperature') || {}).state);
    if (!isNaN(bt)) {
      boostTemp = bt;
      boostUntil = nowMs + BOOST_MS;
      context.set('boostTemp', boostTemp);
      context.set('boostUntil', boostUntil);
    }
  }
}
if (msg.topic === 'boost-cancel' && boostUntil > nowMs) {
  boostUntil = 0; boostTemp = null;
  context.set('boostTemp', null);
  context.set('boostUntil', 0);
  boostNote = 'Boost cancelled - back to schedule';
}

// Cancel any active boost the moment the house goes Away (don't heat an empty house)
if (mode === 'away' && boostUntil > nowMs) { boostUntil = 0; boostTemp = null; }

const boosting = boostUntil > nowMs;
if (!boosting) { context.set('boostUntil', 0); context.set('boostTemp', null); }

const effectiveMode = boosting ? 'boost' : schedMode;
const target = boosting ? boostTemp : schedTarget;

// --- status text (out3; only written when it changes) ---
const statusText = boosting
  ? ('Boost ' + target + '° until ' + hhmm(boostUntil))
  : (hmDisplay + ': ' + effectiveMode + ' ' + target + '°');
let statusMsg = null;
if (statusText !== context.get('lastStatus')) {
  context.set('lastStatus', statusText);
  statusMsg = { statusText: statusText };
}

// --- de-dupe + 30-min re-assert ---
const lastTs = context.get('lastTs') || 0;
const stale = (nowMs - lastTs) > 30 * 60 * 1000;
if (lastTarget === target && !stale) {
  // no thermostat write needed; still surface status changes + boost notes (quiet hours apply)
  let n2 = null;
  if (boostNote && !(hour >= 22 || hour < 7)) n2 = { notify_title: 'Heating', notify_message: boostNote };
  return [null, n2, statusMsg];
}
const changed = (lastTarget !== target);
context.set('lastTarget', target);
context.set('lastTs', nowMs);
context.set('confirmed', false);          // wait for the entity to reflect this new write

msg.target = target;
msg.info = { houseMode: hmDisplay, effectiveMode, target, boosting, longAway };

const boostMins = boosting ? Math.round((boostUntil - nowMs) / 60000) : 0;
node.status({
  fill: boosting ? 'yellow' : (mode === 'away' ? 'blue' : (mode === 'sleeping' ? 'grey' : 'green')),
  shape: 'dot',
  text: boosting ? ('BOOST ' + target + 'C ' + boostMins + 'm left') : (hmDisplay + ' -> ' + effectiveMode + ' ' + target + 'C')
});

// --- test notification: change only, quiet 22:00-07:00 ---
let notifyMsg = null;
const nightQuiet = (hour >= 22 || hour < 7);
if (changed && !nightQuiet) {
  let m;
  if (boostNote) {
    m = boostNote + ' (' + effectiveMode + ' ' + target + 'C)';
  } else if (boosting) {
    m = 'Boost ' + target + 'C, holding until ' + hhmm(boostUntil);
  } else {
    m = hmDisplay + ' -> ' + effectiveMode + ' ' + target + 'C';
  }
  notifyMsg = { notify_title: 'Heating', notify_message: m };
}
return [msg, notifyMsg, statusMsg];

// === Nightly forecast pre-heat decision (~21:30) ===
// Reads the Met Éireann hourly forecast (from heat-fc-get) and decides how early to
// start tomorrow's 07:00 warm-up. Sets flow.preHeat for heat-fn. NO notification (removed 02-07-2026).
const MORNING_HOUR = 7;
const p = msg.payload || {};
let fc = p.forecast
  || (p['weather.forecast_home'] && p['weather.forecast_home'].forecast)
  || (msg.response && msg.response.forecast)
  || [];
if (!Array.isArray(fc)) fc = [];
if (fc.length === 0) {
  node.warn('preheat: forecast empty. msg keys=' + JSON.stringify(Object.keys(msg)) + ' payload keys=' + JSON.stringify(typeof p === 'object' ? Object.keys(p) : typeof p));
}

const now = new Date();
const ds = d => d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0') + '-' + String(d.getDate()).padStart(2, '0');

// tomorrow-morning entries: future, local (Dublin) hour 5..7
const morning = fc
  .map(x => ({ d: new Date(x.datetime), t: x.temperature }))
  .filter(x => x.d > now && x.d.getHours() >= 5 && x.d.getHours() <= 7 && x.t != null);

if (!morning.length) {
  node.warn('preheat: no morning forecast entries (payload shape?)');
  node.status({ fill: 'grey', shape: 'ring', text: 'no forecast' });
  return null;
}

const minTemp = Math.min(...morning.map(x => x.t));
let lead = 0;
if (minTemp < -3) lead = 60;
else if (minTemp < 0) lead = 45;
else if (minTemp < 4) lead = 30;
else if (minTemp < 8) lead = 15;
node.warn('preheat check: fc=' + fc.length + ' morning=' + morning.length + ' minTemp=' + minTemp + ' lead=' + lead);

if (lead === 0) {
  flow.set('preHeat', null);
  node.status({ fill: 'green', shape: 'dot', text: 'no preheat (' + minTemp + 'C)' });
  return null;                       // mild enough -> no early start
}

const day = morning[0].d;
const start = new Date(day.getFullYear(), day.getMonth(), day.getDate(), MORNING_HOUR, 0, 0);
start.setMinutes(start.getMinutes() - lead);
const hhmm = String(start.getHours()).padStart(2, '0') + ':' + String(start.getMinutes()).padStart(2, '0');

flow.set('preHeat', { day: ds(day), startMs: start.getTime(), leadMins: lead, temp: minTemp });
node.status({ fill: 'yellow', shape: 'dot', text: 'preheat ' + hhmm + ' (' + minTemp + 'C)' });

// Notify ONLY when the forecast low is sub-zero / freezing (user 02-07-2026)
if (minTemp < 0) {
  msg.notify_title = '❄️ Freezing morning ahead';
  msg.notify_message = 'Low around ' + minTemp + '°C overnight — I\'ll start warming the house early, from ' + hhmm + '.';
  return msg;
}
return null;                         // above-freezing pre-heat happens silently (no push)
